function Skeleton({
  width,
  depth,
  height,
  message,
  tone = 'busy',
}: {
  width: number;
  depth: number;
  height: number;
  message?: string;
  tone?: 'busy' | 'error';
}) {
  const groupRef = useRef<Group>(null);
  const innerWireRef = useRef<Mesh>(null);
  const outerWireRef = useRef<Mesh>(null);
  const ghostRef = useRef<Mesh>(null);
  const scanRef = useRef<Mesh>(null);
  const haloRef = useRef<Mesh>(null);
  const startedAt = useRef<number>(performance.now());
  const [elapsedSec, setElapsedSec] = useState(0);

  // Tick a 1Hz timer so the badge can show "· 23s" without re-rendering on
  // every frame. The 3D animations all run inside useFrame.
  useEffect(() => {
    if (tone !== 'busy') return;
    const id = setInterval(() => {
      setElapsedSec(Math.floor((performance.now() - startedAt.current) / 1000));
    }, 1000);
    return () => clearInterval(id);
  }, [tone]);

  // Total bounding height = walls + pyramidal roof (35% of height).
  const roofHeight = height * 0.35;
  const totalH = height + roofHeight;

  useFrame(({ clock }) => {
    const t = clock.elapsedTime;
    // Outer group: slow oscillating yaw (sine), feels alive without spinning.
    if (groupRef.current) {
      groupRef.current.rotation.y = Math.sin(t * 0.45) * 0.35;
    }
    // Inner wireframe: counter-rotates faster for parallax.
    if (innerWireRef.current) {
      innerWireRef.current.rotation.y = -t * 0.6;
    }
    // Outer wireframe: gently breathing scale + opacity pulse.
    if (outerWireRef.current) {
      const breath = 1 + Math.sin(t * 2.3) * 0.04;
      outerWireRef.current.scale.set(breath, breath, breath);
      const mat = outerWireRef.current.material as { opacity?: number } | undefined;
      if (mat && 'opacity' in mat) mat.opacity = 0.32 + Math.sin(t * 3) * 0.12;
    }
    // Ghost solid box: very faint, pulses out of phase.
    if (ghostRef.current) {
      const mat = ghostRef.current.material as { opacity?: number } | undefined;
      if (mat && 'opacity' in mat) mat.opacity = 0.06 + (Math.sin(t * 2.3 + Math.PI) + 1) * 0.04;
    }
    // Halo ring on the ground — breathes outward for an "AI thinking" vibe.
    if (haloRef.current) {
      const breath = 1 + (Math.sin(t * 1.8) + 1) * 0.18;
      haloRef.current.scale.set(breath, breath, breath);
      const mat = haloRef.current.material as { opacity?: number } | undefined;
      if (mat && 'opacity' in mat) mat.opacity = 0.32 - (Math.sin(t * 1.8) + 1) * 0.1;
    }
    // Scanning plane sweeps up & down through the volume (0 → totalH).
    if (scanRef.current) {
      const phase = (Math.sin(t * 1.1) + 1) * 0.5; // 0..1
      scanRef.current.position.y = phase * totalH;
      const mat = scanRef.current.material as { opacity?: number } | undefined;
      if (mat && 'opacity' in mat) mat.opacity = 0.55 - Math.abs(phase - 0.5) * 0.4;
    }
  });

  const color = tone === 'error' ? '#dc2626' : '#3b82f6';
  const glow = tone === 'error' ? '#fca5a5' : '#60a5fa';
  const planSize = Math.max(width, depth);

  return (
    <group ref={groupRef}>
      {/* ─── Faint solid ghost so the void doesn't feel empty ─────────── */}
      <mesh ref={ghostRef} position={[0, height / 2, 0]} castShadow={false} receiveShadow={false}>
        <boxGeometry args={[width * 0.98, height * 0.98, depth * 0.98]} />
        <meshBasicMaterial color={color} transparent opacity={0.08} depthWrite={false} />
      </mesh>

      {/* ─── Outer wireframe — main "house" silhouette ─────────────────── */}
      <mesh
        ref={outerWireRef}
        position={[0, height / 2, 0]}
        castShadow={false}
        receiveShadow={false}
      >
        <boxGeometry args={[width, height, depth]} />
        <meshBasicMaterial color={color} transparent opacity={0.32} depthWrite={false} visible={false} />
        <Edges color={color} threshold={1} />
      </mesh>

      {/* ─── Inner counter-rotating wireframe for parallax ────────────── */}
      <mesh ref={innerWireRef} position={[0, height / 2, 0]}>
        <boxGeometry args={[width * 0.7, height * 0.7, depth * 0.7]} />
        <meshBasicMaterial color={glow} transparent opacity={0.0} depthWrite={false} visible={false} />
        <Edges color={glow} threshold={1} />
      </mesh>

      {/* ─── Pyramidal "roof" hint (4-sided cone) ─────────────────────── */}
      <mesh position={[0, height + roofHeight / 2, 0]} rotation={[0, Math.PI / 4, 0]}>
        <coneGeometry args={[planSize * 0.6, roofHeight, 4]} />
        <meshBasicMaterial color={color} transparent opacity={0.0} depthWrite={false} visible={false} />
        <Edges color={color} threshold={1} />
      </mesh>

      {/* ─── Scanning plane — thin glowing rectangle traveling Y ──────── */}
      <mesh ref={scanRef} position={[0, 0, 0]} rotation={[-Math.PI / 2, 0, 0]}>
        <planeGeometry args={[width * 1.15, depth * 1.15]} />
        <meshBasicMaterial
          color={glow}
          transparent
          opacity={0.4}
          depthWrite={false}
          toneMapped={false}
        />
      </mesh>

      {/* ─── Ground halo — breathing ring under the model ─────────────── */}
      <mesh ref={haloRef} position={[0, 0.01, 0]} rotation={[-Math.PI / 2, 0, 0]}>
        <ringGeometry args={[planSize * 0.55, planSize * 0.7, 64]} />
        <meshBasicMaterial color={glow} transparent opacity={0.2} depthWrite={false} toneMapped={false} />
      </mesh>

      {/* ─── Floating badge ──────────────────────────────────────────── */}
      {message && (
        <Html
          position={[0, totalH + height * 0.45, 0]}
          center
          distanceFactor={9}
          style={{ pointerEvents: 'none' }}
          zIndexRange={[16777271, 16777271]}
        >
          <div className={tone === 'error' ? 'tm-card tm-card-error' : 'tm-card tm-card-busy'}>
            <div className="tm-card-bg" />
            <div className="tm-card-inner">
              <div className="tm-orb">
                <span className="tm-orb-core" />
                <span className="tm-orb-ring tm-orb-ring-1" />
                <span className="tm-orb-ring tm-orb-ring-2" />
              </div>
              <div className="tm-text">
                <div className="tm-title">
                  <span className="tm-title-text">{message}</span>
                  {tone === 'busy' && <span className="tm-ellipsis" />}
                </div>
                {tone === 'busy' && (
                  <div className="tm-sub">
                    <span className="tm-bars">
                      <span /><span /><span /><span /><span />
                    </span>
                    <span className="tm-elapsed">
                      {elapsedSec}s elapsed · usually ~45s
                    </span>
                  </div>
                )}
              </div>
            </div>
          </div>
          <style>{`
            .tm-card {
              position: relative;
              padding: 14px 22px;
              border-radius: 18px;
              font: 600 18px/1.2 system-ui, -apple-system, 'Segoe UI', sans-serif;
              white-space: nowrap;
              backdrop-filter: blur(14px) saturate(140%);
              -webkit-backdrop-filter: blur(14px) saturate(140%);
              overflow: hidden;
              box-shadow:
                0 1px 0 rgba(255,255,255,0.6) inset,
                0 12px 36px rgba(15,23,42,0.18),
                0 2px 8px rgba(15,23,42,0.10);
              transform: translateZ(0);
            }
            .tm-card-busy {
              color: #0c1f5a;
              background: linear-gradient(135deg, rgba(255,255,255,0.92) 0%, rgba(241,245,255,0.92) 100%);
              border: 1px solid rgba(59,130,246,0.35);
            }
            .tm-card-error {
              color: #7f1d1d;
              background: linear-gradient(135deg, rgba(255,255,255,0.95) 0%, rgba(254,242,242,0.95) 100%);
              border: 1px solid rgba(220,38,38,0.45);
            }
            /* Animated shimmer streaking diagonally across the card */
            .tm-card-bg {
              position: absolute;
              inset: 0;
              pointer-events: none;
              background: linear-gradient(
                115deg,
                transparent 30%,
                rgba(96,165,250,0.22) 48%,
                rgba(96,165,250,0.08) 52%,
                transparent 70%
              );
              background-size: 220% 100%;
              animation: tm-shimmer 2.6s linear infinite;
              mix-blend-mode: screen;
            }
            .tm-card-error .tm-card-bg {
              background: linear-gradient(
                115deg,
                transparent 30%,
                rgba(248,113,113,0.22) 48%,
                rgba(248,113,113,0.08) 52%,
                transparent 70%
              );
              background-size: 220% 100%;
              animation: tm-shimmer 2.6s linear infinite;
            }
            .tm-card-inner {
              position: relative;
              display: flex;
              align-items: center;
              gap: 14px;
            }
            .tm-text {
              display: flex;
              flex-direction: column;
              gap: 4px;
            }
            .tm-title {
              display: inline-flex;
              align-items: baseline;
              font-size: 20px;
