116	  const startedAt = useRef<number>(performance.now());
117	  const [elapsedSec, setElapsedSec] = useState(0);
118	
119	  // Tick a 1Hz timer so the badge can show "· 23s" without re-rendering on
120	  // every frame. The 3D animations all run inside useFrame.
121	  useEffect(() => {
122	    if (tone !== 'busy') return;
123	    const id = setInterval(() => {
124	      setElapsedSec(Math.floor((performance.now() - startedAt.current) / 1000));
125	    }, 1000);
126	    return () => clearInterval(id);
127	  }, [tone]);
128	
129	  // Total bounding height = walls + pyramidal roof (35% of height).
130	  const roofHeight = height * 0.35;
131	  const totalH = height + roofHeight;
132	
133	  useFrame(({ clock }) => {
134	    const t = clock.elapsedTime;
135	    // Outer group: slow oscillating yaw (sine), feels alive without spinning.
136	    if (groupRef.current) {
137	      groupRef.current.rotation.y = Math.sin(t * 0.45) * 0.35;
138	    }
139	    // Inner wireframe: counter-rotates faster for parallax.
140	    if (innerWireRef.current) {
141	      innerWireRef.current.rotation.y = -t * 0.6;
142	    }
143	    // Outer wireframe: gently breathing scale + opacity pulse.
144	    if (outerWireRef.current) {
145	      const breath = 1 + Math.sin(t * 2.3) * 0.04;
146	      outerWireRef.current.scale.set(breath, breath, breath);
147	      const mat = outerWireRef.current.material as { opacity?: number } | undefined;
148	      if (mat && 'opacity' in mat) mat.opacity = 0.32 + Math.sin(t * 3) * 0.12;
149	    }
150	    // Ghost solid box: very faint, pulses out of phase.
151	    if (ghostRef.current) {
152	      const mat = ghostRef.current.material as { opacity?: number } | undefined;
153	      if (mat && 'opacity' in mat) mat.opacity = 0.06 + (Math.sin(t * 2.3 + Math.PI) + 1) * 0.04;
154	    }
155	    // Halo ring on the ground — breathes outward for an "AI thinking" vibe.
156	    if (haloRef.current) {
157	      const breath = 1 + (Math.sin(t * 1.8) + 1) * 0.18;
158	      haloRef.current.scale.set(breath, breath, breath);
159	      const mat = haloRef.current.material as { opacity?: number } | undefined;
160	      if (mat && 'opacity' in mat) mat.opacity = 0.32 - (Math.sin(t * 1.8) + 1) * 0.1;
161	    }
162	    // Scanning plane sweeps up & down through the volume (0 → totalH).
163	    if (scanRef.current) {
164	      const phase = (Math.sin(t * 1.1) + 1) * 0.5; // 0..1
165	      scanRef.current.position.y = phase * totalH;
166	      const mat = scanRef.current.material as { opacity?: number } | undefined;
167	      if (mat && 'opacity' in mat) mat.opacity = 0.55 - Math.abs(phase - 0.5) * 0.4;
168	    }
169	  });
170	
171	  const color = tone === 'error' ? '#dc2626' : '#3b82f6';
172	  const glow = tone === 'error' ? '#fca5a5' : '#60a5fa';
173	  const planSize = Math.max(width, depth);
174	
175	  return (
176	    <group ref={groupRef}>
177	      {/* ─── Faint solid ghost so the void doesn't feel empty ─────────── */}
178	      <mesh ref={ghostRef} position={[0, height / 2, 0]} castShadow={false} receiveShadow={false}>
