// fal-ai/trellis-2 wrapper. Image → 3D GLB.
// Tuned for web display: smaller mesh + texture so the GLB is < ~2MB.

import { fal } from '@fal-ai/client';

let configured = false;
function ensureConfigured(): void {
  if (configured) return;
  const credentials = process.env.FAL_KEY;
  if (!credentials) throw new Error('FAL_KEY not set');
  fal.config({ credentials });
  configured = true;
}

export interface TrellisInput {
  /** PNG/JPEG buffer of the input image (oblique screenshot of the building). */
  image: Buffer;
}

export interface TrellisResult {
  glbUrl: string;
  requestId: string;
}

export async function generateTrellisModel(input: TrellisInput): Promise<TrellisResult> {
  ensureConfigured();

  // The previous implementation called fal.storage.upload(blob) first, but
  // that endpoint returns 403 Forbidden for some keys (the upload origin is
  // tighter than queue submission). Skip it: fal accepts base64 data URIs
  // directly as `image_url`, which is what the docs recommend for small
  // server-side blobs anyway.
  const dataUri = `data:image/png;base64,${input.image.toString('base64')}`;

  try {
    const result = await fal.subscribe('fal-ai/trellis-2', {
      input: {
        image_url: dataUri,
        decimation_target: 30000,
        texture_size: '1024',
        resolution: '1024',
      },
      logs: false,
    });
    const glbUrl = result.data?.model_glb?.url;
    if (!glbUrl) throw new Error('trellis returned no model_glb url');
    return { glbUrl, requestId: result.requestId };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    // Surface fal-side validation errors (often HTTP 422 with body details).
    const detail =
      err && typeof err === 'object' && 'body' in err
        ? ` body=${JSON.stringify((err as { body: unknown }).body)}`
        : '';
    throw new Error(`fal.subscribe(trellis-2) failed: ${msg}${detail}`);
  }
}

input.new_string:
// fal-ai/trellis-2 wrapper. Image → 3D GLB via the raw queue API.
//
// We bypass @fal-ai/client because its fal.subscribe() / fal.storage.upload()
// hit an auth-check pipeline that returns 403 Forbidden ("User is locked")
// for our key, even though the underlying queue.fal.run endpoint accepts the
// exact same Bearer credentials with HTTP 200. Going through the queue API
// directly avoids that entirely.

const QUEUE_BASE = 'https://queue.fal.run';
const MODEL_ID = 'fal-ai/trellis-2';
// Cap the polling so a wedged request doesn't tie up the route forever.
// Trellis-2 typically completes in 30-60s; 4 minutes is generous.
const MAX_POLL_MS = 240_000;
const POLL_INTERVAL_MS = 2_000;

export interface TrellisInput {
  /** PNG/JPEG buffer of the input image (oblique screenshot of the building). */
  image: Buffer;
}

export interface TrellisResult {
  glbUrl: string;
  requestId: string;
}

interface QueueSubmitResponse {
  status?: string;
  request_id: string;
  status_url: string;
  response_url: string;
}

interface QueueStatusResponse {
  status: 'IN_QUEUE' | 'IN_PROGRESS' | 'COMPLETED' | 'FAILED' | 'CANCELLED';
  queue_position?: number;
  logs?: Array<{ message: string }>;
  metrics?: Record<string, unknown>;
}

interface TrellisOutput {
  model_glb?: { url?: string };
}

function authHeader(): string {
  const key = process.env.FAL_KEY;
  if (!key) throw new Error('FAL_KEY not set');
  return `Key ${key}`;
}

export async function generateTrellisModel(input: TrellisInput): Promise<TrellisResult> {
  const dataUri = `data:image/png;base64,${input.image.toString('base64')}`;

  // 1. Submit to the queue.
  const submitRes = await fetch(`${QUEUE_BASE}/${MODEL_ID}`, {
    method: 'POST',
    headers: {
      Authorization: authHeader(),
      'content-type': 'application/json',
    },
    body: JSON.stringify({
      image_url: dataUri,
      decimation_target: 30000,
      texture_size: '1024',
      resolution: '1024',
    }),
  });
  if (!submitRes.ok) {
    const body = await submitRes.text().catch(() => '');
    throw new Error(`queue submit failed: HTTP ${submitRes.status} ${body}`);
  }
  const submit = (await submitRes.json()) as QueueSubmitResponse;
  const { request_id, status_url, response_url } = submit;
  if (!request_id || !status_url || !response_url) {
    throw new Error(`queue submit returned malformed body: ${JSON.stringify(submit)}`);
  }

  // 2. Poll status_url until terminal.
  const startedAt = Date.now();
  while (Date.now() - startedAt < MAX_POLL_MS) {
    await sleep(POLL_INTERVAL_MS);
    const statusRes = await fetch(status_url, {
      headers: { Authorization: authHeader() },
    });
    if (!statusRes.ok) {
      const body = await statusRes.text().catch(() => '');
      throw new Error(`queue status failed: HTTP ${statusRes.status} ${body}`);
    }
    const status = (await statusRes.json()) as QueueStatusResponse;
    if (status.status === 'COMPLETED') break;
    if (status.status === 'FAILED' || status.status === 'CANCELLED') {
      throw new Error(`trellis ${status.status.toLowerCase()}: ${JSON.stringify(status)}`);
    }
  }
  if (Date.now() - startedAt >= MAX_POLL_MS) {
    throw new Error(`trellis timed out after ${Math.round(MAX_POLL_MS / 1000)}s`);
  }

  // 3. Fetch the result.
  const resultRes = await fetch(response_url, {
    headers: { Authorization: authHeader() },
  });
  if (!resultRes.ok) {
    const body = await resultRes.text().catch(() => '');
    throw new Error(`queue result failed: HTTP ${resultRes.status} ${body}`);
  }
  const output = (await resultRes.json()) as TrellisOutput;
  const glbUrl = output.model_glb?.url;
  if (!glbUrl) throw new Error(`trellis returned no model_glb.url: ${JSON.stringify(output)}`);

  return { glbUrl, requestId: request_id };
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

