// Real-pipeline orchestrator. Replaces the previous mocked 22s sequence with
// 3 explicit steps tied to the actual underlying network calls so the
// AgentTrace narrates what's truly happening:
//
//   1. CAPTURE  — /api/aerial?tilted=1 → oblique screenshot via Cesium +
//                 Google Photorealistic 3D Tiles (Playwright headless).
//                 The screenshot is shown as a thumbnail next to the step
//                 once the image loads in the browser.
//   2. SIZE     — /api/design  → k-NN sizing over the Reonic dataset +
//                 financial model (price, payback, CO₂).
//   3. MODEL    — fal-ai/trellis-2 image-to-3D via /api/trellis. Mirrors
//                 the trellisStatus written by <TrellisModel/>.
//
// Steps run in parallel under the hood; the trace renders them sequentially
// because that's what reads as a clear story to the user. Phase flips to
// 'interactive' only once all three are done.

'use client';

import { useEffect } from 'react';
import { useStore } from '@/lib/store';
import type { AgentStep } from '@/lib/types';
import { HOUSE_COORDS } from './vision/houseLatLng';
import type { HouseId } from '@/lib/types';

export interface SeqStep {
  id: 'capture' | 'size' | 'model';
  label: string;
  sublabel: string;
  /** Estimated wall-clock in ms — only feeds the progress bar; the actual
   *  running state lasts until the step's promise resolves. */
  estDurationMs: number;
}

export const SEQUENCE: SeqStep[] = [
  {
    id: 'capture',
    label: 'Capturing oblique aerial view',
    sublabel: 'Cesium + Google Photorealistic 3D Tiles',
    estDurationMs: 12_000,
  },
  {
    id: 'size',
    label: 'Computing solar sizing & financial model',
    sublabel: 'k-NN over 1,620 Reonic deliveries',
    estDurationMs: 1_200,
  },
  {
    id: 'model',
    label: 'Reconstructing 3D building',
    sublabel: 'fal-ai/trellis-2 — image to GLB (~30-60s)',
    estDurationMs: 45_000,
  },
];

function resolveCoords(
  selectedHouse: HouseId | 'custom' | null,
  customLat?: number,
  customLng?: number,
): { lat: number; lng: number } | null {
  if (!selectedHouse) return null;
  if (selectedHouse === 'custom') {
    if (customLat == null || customLng == null) return null;
    return { lat: customLat, lng: customLng };
  }
  const c = HOUSE_COORDS[selectedHouse];
  return c ? { lat: c.lat, lng: c.lng } : null;
}

export function Orchestrator() {
  const phase = useStore((s) => s.phase);
  const profile = useStore((s) => s.profile);
  const selectedHouse = useStore((s) => s.selectedHouse);
  const customAddress = useStore((s) => s.customAddress);
  const setAgentSteps = useStore((s) => s.setAgentSteps);
  const updateStepStatus = useStore((s) => s.updateStepStatus);
  const updateStepFields = useStore((s) => s.updateStepFields);
  const setPhase = useStore((s) => s.setPhase);
  const setDesign = useStore((s) => s.setDesign);
  const setCustomRoofGeometry = useStore((s) => s.setCustomRoofGeometry);

  useEffect(() => {
    if (phase !== 'agent-running' || !profile || !selectedHouse) return;

    // Initial step list — all pending. AgentTrace renders directly off this.
    const steps: AgentStep[] = SEQUENCE.map((s) => ({
      id: s.id,
      label: s.label,
      sublabel: s.sublabel,
      durationMs: s.estDurationMs,
      status: 'pending',
    }));
    setAgentSteps(steps);

    let cancelled = false;
    const coords = resolveCoords(
      selectedHouse,
      customAddress?.lat,
      customAddress?.lng,
    );

    // ── Step 1: aerial capture ───────────────────────────────────────────
    // We trigger the same /api/aerial?tilted=1 endpoint that <TrellisModel/>
    // also pulls server-side. Using `new Image()` we get an onLoad event
    // when the screenshot is fully decoded by the browser; the URL doubles
    // as the artifact thumbnail because subsequent <img> renders hit the
    // browser cache instantly.
    const aerialPromise: Promise<void> = (async () => {
      if (!coords) return;
      const url = `/api/aerial?lat=${coords.lat}&lng=${coords.lng}&zoom=20&tilted=1`;
      updateStepStatus('capture', 'running');
      await new Promise<void>((resolve) => {
        const img = new Image();
        img.onload = () => {
          if (cancelled) return resolve();
          updateStepFields('capture', { status: 'done', artifactUrl: url });
          resolve();
        };
        img.onerror = () => {
          if (cancelled) return resolve();
          updateStepFields('capture', { status: 'error' });
          resolve();
        };
        img.src = url;
      });
    })();

    // ── Step 2: sizing + financials via /api/design ──────────────────────
    const body: Record<string, unknown> = { profile, houseId: selectedHouse };
    if (selectedHouse === 'custom' && customAddress) {
      body.lat = customAddress.lat;
      body.lng = customAddress.lng;
      body.address = customAddress.formatted;
    }
    const designPromise = (async () => {
      updateStepStatus('size', 'running');
      try {
        const r = await fetch('/api/design', {
          method: 'POST',
          headers: { 'content-type': 'application/json' },
          body: JSON.stringify(body),
        });
        const design = r.ok ? await r.json() : null;
        if (cancelled) return null;
        if (design?.geometry) setCustomRoofGeometry(design.geometry);
        if (design) {
          setDesign(design);
          const totalKwp = Number(design.totalKwp);
          const price = Number(design.totalPriceEur);
          const payback = Number(design.paybackYears);
          const summary =
            Number.isFinite(totalKwp) && Number.isFinite(price) && Number.isFinite(payback)
              ? `${totalKwp.toFixed(1)} kWp · €${price.toLocaleString()} · ${payback.toFixed(1)}y payback`
              : undefined;
          updateStepFields('size', { status: 'done', resultLine: summary });
        } else {
          updateStepFields('size', { status: 'error' });
        }
        return design;
      } catch {
        if (cancelled) return null;
        updateStepFields('size', { status: 'error' });
        return null;
      }
    })();

    // ── Step 3: Trellis-2 image-to-3D ────────────────────────────────────
    // <TrellisModel/> mounts when Scene3D mounts (i.e. before the user even
    // clicked Generate), so trellisStatus may already be 'generating' or
    // even 'ready' by the time we get here. Mirror it.
    const modelPromise: Promise<void> = (async () => {
      const initial = useStore.getState().trellisStatus;
      if (initial === 'ready') {
        updateStepFields('model', { status: 'done', resultLine: 'GLB ready' });
        return;
      }
      if (initial === 'error') {
        updateStepFields('model', { status: 'error' });
        return;
      }
      updateStepStatus('model', 'running');
      while (!cancelled) {
        const t = useStore.getState().trellisStatus;
        if (t === 'ready') {
          updateStepFields('model', { status: 'done', resultLine: 'GLB ready' });
          return;
        }
        if (t === 'error') {
          updateStepFields('model', { status: 'error' });
          return;
        }
        await new Promise((r) => setTimeout(r, 250));
      }
    })();

    // Flip to interactive once all three steps have settled.
    Promise.all([aerialPromise, designPromise, modelPromise]).then(() => {
      if (!cancelled) setPhase('interactive');
    });

    return () => {
      cancelled = true;
    };
  }, [
    phase,
    profile,
    selectedHouse,
    customAddress,
    setAgentSteps,
    updateStepStatus,
    updateStepFields,
    setPhase,
    setDesign,
    setCustomRoofGeometry,
  ]);

  return null;
}

