'use client';

import dynamic from 'next/dynamic';

const ObliqueTiles = dynamic(
  () => import('./ObliqueTiles').then((m) => m.ObliqueTiles),
  { ssr: false },
);

export default function ObliquePage() {
  return <ObliqueTiles />;
}

